<template>
 <svg>
   <use :xlink:href='getHrefIcon'></use>
 </svg>
</template>

<script>
import spriteSvg from '../../assets/images/sprite.svg'

export default {
  name: 'd-icon',
  data () {
    return {
      spriteSvg: spriteSvg
    }
  },
  props: {
    iconName: {
      require: true,
      type: String,
      default: 'NONE'
    }
  },
  computed: {
    getHrefIcon () {
      return `${this.spriteSvg}#${this.iconName}`
    }
  }
}
</script>
